mapper.select:
select * from ( select 'ISSUE_STATUS' as option_group, null as issue_type_id, null as initial_status_id, null as issue_type_name, null as roadmap_yn, null as description, null as created_at, null as updated_at, user_id, null as initial_status_name, issue_status_id, status_name, null as project_id, null as project_name, 1 as option_sort, row_number() over (order by issue_status_id asc) as row_sort from issue_status where user_id = #{userId}
union all
select 'PROJECT' as option_group, null as issue_type_id, null as initial_status_id, null as issue_type_name, null as roadmap_yn, null as description, null as created_at, null as updated_at, owner_id as user_id, null as initial_status_name, null as issue_status_id, null as status_name, project_id, project_name, 2 as option_sort, row_number() over (order by created_at desc, project_name) as row_sort from project where owner_id = #{userId} ) order by option_sort, row_sort

select
(
select count(*)
from issue_type
where user_id = #{userId}
and issue_type_name = #{issueTypeName}
) as duplicate_count,
(
select count(*)
from issue_status
where issue_status_id = #{initialStatusId}
and user_id = #{userId}
) as initial_status_count,


		(
		select count(distinct project_id)
		from project
		where owner_id = #{userId}
		and project_id in

			#{projectId}

		) as selected_project_count


		0 as selected_project_count


from dual

select
count(*)
